-- ═══════════════════════════════════════════════════════════════════
-- CodeQuest · Migración 046 — SQL con Oracle · m11: Proyecto integrador
-- ═══════════════════════════════════════════════════════════════════
-- Parte XIII — CIERRE DEL CURSO. El encargo completo: el programa de
-- vacunación del hospital, recorrido de punta a punta con un caso
-- NUEVO que obliga a usar todo el arsenal: brief → requisitos →
-- modelo (UID con tiempo, identificadora, 3FN, arco) → esquema
-- Oracle (PK compuesta, FKs nombradas) → consultas (joins de 3
-- tablas + GROUP BY/HAVING) → operación y seguridad (procedure como
-- aduana, transacción atómica, trigger de auditoría, estadísticas)
-- → matriz CRUD de validación → examen final del curso completo.
-- Estructura de capstone: 1 lección de arranque, 4 PRÁCTICAS
-- encadenadas, 1 lección de cierre con retrospectiva, examen final.
-- Reglas de contenido: quizzes autocontenidos o con términos técnicos.
-- OJO: SQL con Oracle está PUBLICADO — esta migración sale en vivo.
-- Idempotente: borra y recrea las lecciones de ESTE módulo.
-- Ejecutar DESPUÉS de 011 (estructura v2).
-- ═══════════════════════════════════════════════════════════════════

-- Limpia el módulo (cascade borra sus content_blocks)
delete from public.lessons
where module_id = (
  select m.id
  from public.modules m
  join public.courses c on c.id = m.course_id
  where c.slug = 'sql-oracle' and m.slug = 'm11-proyecto-integrador'
);

-- ── Lecciones del módulo ──────────────────────────────────────────────
insert into public.lessons (module_id, slug, title, kind, xp, sort_order)
select m.id, v.slug, v.title, v.kind, v.xp, v.ord
from public.modules m
join public.courses c on c.id = m.course_id,
     (values
       ('m11-l01-encargo',            'El encargo: programa de vacunación',  'leccion',  20, 1),
       ('m11-l02-practica-modelo',    'Práctica: el modelo del programa',    'practica', 20, 2),
       ('m11-l03-practica-ddl',       'Práctica: el esquema en Oracle',      'practica', 20, 3),
       ('m11-l04-practica-consultas', 'Práctica: el tablero de cobertura',   'practica', 20, 4),
       ('m11-l05-practica-operacion', 'Práctica: operación y seguridad',     'practica', 20, 5),
       ('m11-l06-crud-cierre',        'La matriz CRUD y el cierre',          'leccion',  20, 6),
       ('m11-x01-examen',             'Examen final: el proyecto completo',  'examen',   40, 7)
     ) as v(slug, title, kind, xp, ord)
where c.slug = 'sql-oracle' and m.slug = 'm11-proyecto-integrador';

-- ═════════════════════════════════════════════════════════════════════
-- L01 · El encargo: programa de vacunación
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"La entrevista con la directora","body":"El hospital San Rafael te contrató para SU siguiente sistema, y esta vez el proyecto es tuyo de punta a punta. La directora médica lo cuenta así: 'Arrancamos el PROGRAMA DE VACUNACIÓN. Manejamos un catálogo de VACUNAS; cada vacuna nos llega en LOTES con número, caducidad y cantidad de dosis — un lote es de una sola vacuna, y sin ella ni siquiera tiene sentido nombrarlo. Organizamos CAMPAÑAS por temporada, cada una en el hospital O en la unidad móvil, nunca ambos. Y registramos cada APLICACIÓN: qué paciente recibió qué lote y cuándo — ojo: la misma persona puede recibir la misma vacuna otra vez en otra fecha, refuerzos. Las brigadas capturan desde tabletas, a veces con mala señal. Y auditoría nos exige saber quién movió qué en los lotes.' Ese párrafo es tu materia prima: el resto del módulo lo convierte, práctica a práctica, en un sistema."}$j$),
  (2, 'texto', $j${"title":"Del párrafo al plan: el método de siempre","body":"El método que ya dominas, ahora sin ruedas de entrenamiento. Los SUSTANTIVOS del negocio insinúan entidades: vacuna, lote, campaña, aplicación, paciente (que YA existe en el hospital — dato importante). Las REGLAS insinúan estructura y constraints: 'un lote es de una sola vacuna y no existe sin ella' huele a relación identificadora; 'hospital O unidad móvil, nunca ambos' es un arco de manual; 'la misma persona, la misma vacuna, otra fecha' te grita que el tiempo entra al UID. Los VERBOS insinúan procesos — capturar aplicaciones, recibir lotes, reportar cobertura — que la matriz CRUD validará al final. Y las CONDICIONES OPERATIVAS (tabletas con mala señal, auditoría) deciden transacciones, seguridad y triggers. El orden del trabajo es el SDLC del m3b: modelo → esquema → consultas → operación → validación. Cada práctica de este módulo es una etapa."}$j$),
  (3, 'texto', $j${"title":"Las reglas de negocio, en limpio","body":"Antes de modelar, el analista pone las reglas por escrito — tu lista de requisitos, la que defenderás en cada práctica: (R1) una VACUNA tiene muchos LOTES; el lote pertenece a exactamente una vacuna, no existe sin ella, y su identidad se compone con ella. (R2) una APLICACIÓN conecta paciente + lote + fecha; la pareja paciente-lote PUEDE repetirse en fechas distintas (refuerzos). (R3) la CAMPAÑA ocurre en el hospital o en la unidad móvil — exactamente uno, y ambas sedes no se parecen en nada. (R4) registrar una aplicación implica también DESCONTAR una dosis del lote — o pasa todo, o no pasa nada. (R5) las brigadas NO tocan tablas directamente. (R6) todo cambio en LOTES deja huella de auditoría: valor anterior, nuevo y cuándo. Seis reglas, seis decisiones que ya sabes tomar — el módulo entero consiste en tomarlas bien."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"En el análisis de un brief de negocio, ¿qué insinúan los SUSTANTIVOS, las REGLAS y los VERBOS?","options":["Nada: el brief se ignora y se modela desde cero","Sustantivos → ENTIDADES candidatas · reglas → ESTRUCTURA y constraints · verbos → PROCESOS que la matriz CRUD validará","Sustantivos → columnas · verbos → índices","Solo importan los números"],"correctIndex":1,"feedback":{"correct":"Correcto. El brief es materia prima estructurada: cada categoría gramatical apunta a una pieza del diseño.","incorrect":"El método del analista: sustantivos a entidades, reglas a estructura/constraints, verbos a procesos — y el CRUD valida que nada falte."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"'Registrar una aplicación implica también descontar la dosis del lote — o pasa todo, o no pasa nada.' ¿Qué pieza técnica del curso describe EXACTAMENTE ese requisito?","options":["Un índice compuesto","Una TRANSACCIÓN atómica: las dos operaciones son una unidad de negocio indivisible — el todo-o-nada de ACID","Una vista de solo lectura","Un sinónimo"],"correctIndex":1,"feedback":{"correct":"Correcto. La regla R4 es la atomicidad con otras palabras: el brief te dictó la frontera del COMMIT.","incorrect":"'O pasa todo o no pasa nada' = transacción atómica: la aplicación y el descuento viven entre el mismo inicio y el mismo COMMIT."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"El programa usará a los PACIENTES que ya existen en el sistema central del hospital. ¿Qué significa eso para tu modelo?","options":["Hay que crear una tabla pacientes nueva para el programa","La entidad paciente NO se re-crea: el programa se RELACIONA con ella (FKs hacia la tabla existente) — duplicarla sembraría la redundancia que la normalización prohíbe","Se copian los pacientes cada noche","Los pacientes no participan del modelo"],"correctIndex":1,"feedback":{"correct":"Correcto. La entidad ya tiene casa: tu modelo la referencia. Una segunda tabla de pacientes es la anomalía del m03 esperando fecha.","incorrect":"Los datos existentes se REFERENCIAN, no se duplican: las FKs de tu programa apuntan a la tabla pacientes que ya vive en el hospital."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — El encargo","points":["El brief de la directora es la materia prima: sustantivos → entidades, reglas → estructura, verbos → procesos.","Seis reglas (R1-R6): identificadora, tiempo en el UID, arco, transacción atómica, acceso por aduana, auditoría.","PACIENTE ya existe: se referencia con FKs, jamás se duplica.","El plan es el SDLC completo: modelo → esquema → consultas → operación → validación CRUD.","Cada práctica del módulo es una etapa del proyecto: sin ruedas de entrenamiento."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm11-l01-encargo';

-- ═════════════════════════════════════════════════════════════════════
-- L02 · Práctica: el modelo del programa (kind = practica)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'ejercicio', $j${"scenario":"Etapa 1 del proyecto: las decisiones de modelado del programa de vacunación. El caso 1 viene resuelto de ejemplo; completa los demás con la respuesta exacta (en minúsculas, tal como aparece en las opciones de cada caso).","instructions":["Caso 2 — R1: el LOTE pertenece a UNA vacuna, no existe sin ella y su identidad se compone con ella. ¿Qué tipo de relación es VACUNA–LOTE? (comun / identificadora / recursiva)","Caso 3 — R2: la misma pareja paciente-lote puede repetirse en fechas distintas (refuerzos). ¿Qué completa el UID de APLICACIÓN además de las dos relaciones? (escribe una palabra)","Caso 4 — Un diseñador propone guardar nombre_vacuna DENTRO de APLICACIÓN ('para no joinear'). Ese dato llega vía el lote: ¿qué forma normal violaría? (1fn / 2fn / 3fn)","Caso 5 — R3: la campaña ocurre en el HOSPITAL o en la UNIDAD MÓVIL, exactamente uno, y las sedes no comparten atributos. ¿Estructura de modelado? (arco / subtipos / recursiva)"],"initialCode":"-- HOJA DE MODELADO — Programa de vacunación\n\n-- Caso 1 (ejemplo): VACUNA (catálogo) tiene muchos LOTES\ncaso1_cardinalidad=uno_a_muchos\n\n-- Caso 2: el lote no existe sin su vacuna (identidad incluida)\ncaso2_relacion=?\n\n-- Caso 3: UID de APLICACION = paciente + lote + ______\ncaso3_uid=?\n\n-- Caso 4: nombre_vacuna dentro de APLICACION violaría la...\ncaso4_viola=?\n\n-- Caso 5: hospital O unidad móvil, exactamente uno\ncaso5_estructura=?","validators":["caso2_relacion\\s*=\\s*identificadora\\b","caso3_uid\\s*=\\s*fecha\\w*","caso4_viola\\s*=\\s*3fn\\b","caso5_estructura\\s*=\\s*arco\\b"],"mockOutput":{"columns":["CASO","DECISIÓN","POR QUÉ"],"rows":[["1 · VACUNA–LOTE","uno_a_muchos","una vacuna, muchos lotes: la cardinalidad del catálogo"],["2 · identidad del lote","identificadora","la barra: 'te necesito para mi UID' — dependencia existencial con identidad compuesta"],["3 · UID de APLICACION","fecha","el tiempo entra al UID: sin la fecha, el refuerzo sería un 'duplicado' prohibido"],["4 · nombre_vacuna copiado","3fn","dato de la vacuna viajando vía lote: dependencia transitiva — se consulta con JOIN, no se copia"],["5 · sede de campaña","arco","exactamente-una entre alternativas sin parentesco: el OR exclusivo"]],"note":"El modelo del programa quedó decidido: identificadora, tiempo en el UID, cero redundancia y un arco. La siguiente etapa lo aterriza en Oracle."},"hints":["Caso 2: 'no existe sin ella Y su identidad se compone con ella' — es más que dependencia existencial: es la barra del módulo de identidad.","Caso 3: ¿qué permite que el mismo paciente reciba el mismo lote otra vez sin violar la unicidad? Caso 4: el dato pertenece a VACUNA y llega a APLICACION pasando por LOTE — transitiva.","Caso 5: alternativas excluyentes SIN atributos comunes → arco (con subtipos habría herencia que aprovechar, y aquí no la hay)."],"successMessage":"Etapa de modelado cerrada: leíste las reglas de la directora y las convertiste en estructura — identificadora, tiempo en el UID, 3FN defendida y un arco bien elegido. El comité aprobó tu ERD: siguiente etapa, el DDL.","failMessage":"Revisa contra las reglas: caso2=identificadora (identidad compuesta con el padre) · caso3=fecha (el refuerzo exige el tiempo en el UID) · caso4=3fn (transitiva vía lote) · caso5=arco (exactamente-una sin parentesco)."}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm11-l02-practica-modelo';

-- ═════════════════════════════════════════════════════════════════════
-- L03 · Práctica: el esquema en Oracle (kind = practica)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'ejercicio', $j${"scenario":"Etapa 2: el mapeo aprobado se vuelve DDL. Las tablas vacunas, lotes y pacientes ya existen; te toca blindar APLICACIONES — la intersección histórica del modelo, con el tiempo en su PK (decisión del caso 3 de la etapa anterior).","instructions":["PK COMPUESTA a nivel tabla (el tiempo en el UID): CONSTRAINT apl_pk PRIMARY KEY (paciente_id, lote_id, fecha_aplicacion).","FK nombrada hacia pacientes: CONSTRAINT apl_pac_fk FOREIGN KEY (paciente_id) REFERENCES pacientes (paciente_id).","FK nombrada hacia lotes: CONSTRAINT apl_lote_fk FOREIGN KEY (lote_id) REFERENCES lotes (lote_id)."],"initialCode":"-- El registro de aplicaciones: la intersección histórica.\n-- Completa las constraints (a nivel tabla, después de las columnas).\n\nCREATE TABLE aplicaciones (\n  paciente_id       NUMBER(6)     NOT NULL,\n  lote_id           NUMBER(6)     NOT NULL,\n  fecha_aplicacion  DATE          NOT NULL,\n  reaccion_adversa  VARCHAR2(200)\n);","validators":["constraint\\s+apl_pk\\s+primary\\s+key\\s*\\(\\s*paciente_id\\s*,\\s*lote_id\\s*,\\s*fecha_aplicacion\\s*\\)","constraint\\s+apl_pac_fk\\s+foreign\\s+key\\s*\\(\\s*paciente_id\\s*\\)\\s+references\\s+pacientes\\s*\\(\\s*paciente_id\\s*\\)","constraint\\s+apl_lote_fk\\s+foreign\\s+key\\s*\\(\\s*lote_id\\s*\\)\\s+references\\s+lotes\\s*\\(\\s*lote_id\\s*\\)"],"mockOutput":{"columns":["RESULTADO"],"rows":[["Table APLICACIONES created."]],"note":"La intersección histórica, blindada: la PK de tres columnas permite el refuerzo legítimo (misma pareja, otra fecha) y prohíbe el duplicado real (misma pareja, misma fecha); las FKs amarran cada aplicación a un paciente y un lote existentes. Las tres constraints con nombre: los errores de producción hablarán claro."},"hints":["La PK compuesta SOLO puede declararse a nivel tabla: CONSTRAINT apl_pk PRIMARY KEY (paciente_id, lote_id, fecha_aplicacion) — después de las columnas, separada por coma.","Las FKs a nivel tabla llevan FOREIGN KEY (columna) REFERENCES tabla (columna) — y su nombre ANTES: CONSTRAINT apl_pac_fk FOREIGN KEY …","Recuerda cerrar cada constraint con coma (salvo la última) y verificar los nombres exactos: apl_pk, apl_pac_fk, apl_lote_fk."],"successMessage":"Esquema en pie: la decisión de modelado (el tiempo en el UID) se volvió una PK compuesta real, y las FKs nombradas amarran el registro a sus padres. El modelo y el metal por fin coinciden — siguiente etapa: hacerle preguntas.","failMessage":"Revisa las tres constraints a nivel tabla y sus nombres exactos: apl_pk PRIMARY KEY (paciente_id, lote_id, fecha_aplicacion) · apl_pac_fk FOREIGN KEY (paciente_id) REFERENCES pacientes (paciente_id) · apl_lote_fk FOREIGN KEY (lote_id) REFERENCES lotes (lote_id)."}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm11-l03-practica-ddl';

-- ═════════════════════════════════════════════════════════════════════
-- L04 · Práctica: el tablero de cobertura (kind = practica)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'ejercicio', $j${"scenario":"Etapa 3: la dirección quiere el tablero de cobertura — dosis aplicadas POR VACUNA, solo las vacunas con campaña real (100 dosis o más), la más aplicada primero. El dato del nombre vive en vacunas; el camino pasa por lotes (la 3FN que defendiste en el modelado ahora se recorre con JOINs). Usa los alias a, l y v.","instructions":["Proyecta: v.nombre y COUNT(*) con alias dosis (usa AS).","FROM aplicaciones a.","JOIN lotes l ON l.lote_id = a.lote_id — el primer tramo del camino.","JOIN vacunas v ON v.vacuna_id = l.vacuna_id — el segundo tramo.","Agrupa por v.nombre, conserva solo los grupos con COUNT(*) >= 100, y ordena por dosis DESC."],"initialCode":"-- Tablero de cobertura: dosis por vacuna (mínimo 100),\n-- la más aplicada primero. Alias: a, l, v.\n\nSELECT v.nombre\nFROM   aplicaciones a;","validators":["select\\s+v\\.nombre\\s*,\\s*count\\s*\\(\\s*\\*\\s*\\)\\s+as\\s+dosis","from\\s+aplicaciones\\s+a\\b","join\\s+lotes\\s+l\\s+on\\s+(l\\.lote_id\\s*=\\s*a\\.lote_id|a\\.lote_id\\s*=\\s*l\\.lote_id)","join\\s+vacunas\\s+v\\s+on\\s+(v\\.vacuna_id\\s*=\\s*l\\.vacuna_id|l\\.vacuna_id\\s*=\\s*v\\.vacuna_id)","group\\s+by\\s+v\\.nombre","having\\s+count\\s*\\(\\s*\\*\\s*\\)\\s*>=\\s*100","order\\s+by\\s+dosis\\s+desc"],"mockOutput":{"columns":["NOMBRE","DOSIS"],"rows":[["Influenza estacional","482"],["Hepatitis B","217"],["Tétanos","134"]],"note":"El tablero de la dirección: cada dosis encontró el nombre de su vacuna recorriendo aplicaciones → lotes → vacunas (el camino que la 3FN pavimentó), el HAVING descartó las campañas incipientes y el DESC puso la cobertura líder arriba."},"hints":["El camino del dato: aplicaciones se une a lotes por lote_id, y lotes a vacunas por vacuna_id — dos JOINs encadenados.","Después de los JOINs: GROUP BY v.nombre (la regla de oro: v.nombre no es agregada, así que se agrupa) y HAVING COUNT(*) >= 100 (condición de grupo, no de fila).","Cierra con ORDER BY dosis DESC. Orden completo: SELECT → FROM → JOINs → GROUP BY → HAVING → ORDER BY."],"successMessage":"Tablero entregado: dos JOINs recorriendo el modelo normalizado, agregación por grupo, HAVING filtrando campañas reales y orden explícito. La consulta que junta medio curso en diez líneas — y la dirección tiene su cobertura.","failMessage":"Revisa el camino completo: SELECT v.nombre, COUNT(*) AS dosis · FROM aplicaciones a · JOIN lotes l ON l.lote_id = a.lote_id · JOIN vacunas v ON v.vacuna_id = l.vacuna_id · GROUP BY v.nombre · HAVING COUNT(*) >= 100 · ORDER BY dosis DESC."}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm11-l04-practica-consultas';

-- ═════════════════════════════════════════════════════════════════════
-- L05 · Práctica: operación y seguridad (kind = practica)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'ejercicio', $j${"scenario":"Etapa 4: el sistema entra en operación y toca decidir cómo se protege. El caso 1 viene resuelto de ejemplo; completa los demás con la respuesta exacta (en minúsculas, tal como aparece en las opciones de cada caso).","instructions":["Caso 2 — R5: las brigadas registran aplicaciones pero NO deben tocar tablas directamente. ¿Cómo se les da acceso? (update_directo / procedure / with_grant_option)","Caso 3 — R4: insertar la aplicación Y descontar la dosis del lote — o pasa todo o no pasa nada. ¿En cuántas transacciones? (una / dos / una_por_tabla)","Caso 4 — R6: cada cambio en LOTES debe dejar huella automática (valor viejo, nuevo, cuándo) sin depender de las aplicaciones. ¿La herramienta? (check / trigger / vista)","Caso 5 — Tras cargar el censo de 2 millones de pacientes, el tablero de cobertura se arrastra. ¿El primer remedio? (hint / estadisticas / mas_indices)"],"initialCode":"-- HOJA DE OPERACIÓN — Programa de vacunación\n\n-- Caso 1 (ejemplo): la cantidad de dosis de un lote\n--   jamás puede ser negativa → restricción declarativa\ncaso1_herramienta=check\n\n-- Caso 2: brigadas sin acceso directo a tablas\ncaso2_acceso=?\n\n-- Caso 3: aplicación + descuento de dosis\ncaso3_transacciones=?\n\n-- Caso 4: huella automática de cambios en lotes\ncaso4_herramienta=?\n\n-- Caso 5: tablero lento tras la carga del censo\ncaso5_remedio=?","validators":["caso2_acceso\\s*=\\s*procedure\\b","caso3_transacciones\\s*=\\s*una\\b","caso4_herramienta\\s*=\\s*trigger\\b","caso5_remedio\\s*=\\s*estadisticas\\b"],"mockOutput":{"columns":["CASO","DECISIÓN","POR QUÉ"],"rows":[["1 · dosis >= 0","check","declarativas antes que triggers: barata, siempre activa, inesquivable"],["2 · acceso de brigadas","procedure","GRANT EXECUTE sin permisos de tabla: la aduana única con validaciones — mínimo privilegio"],["3 · aplicación + descuento","una","unidad de negocio indivisible: ambas operaciones entre el mismo inicio y el mismo COMMIT"],["4 · huella de lotes","trigger","el journaling con :OLD/:NEW: automático y a prueba de aplicaciones olvidadizas"],["5 · tablero lento tras carga","estadisticas","la carga invalidó la foto: DBMS_STATS antes de tocar índices o SQL"]],"note":"La operación quedó blindada: cada regla con SU herramienta, ninguna herramienta fuera de su lugar."},"hints":["Caso 2: la tabla cerrada y una sola puerta pavimentada — ¿qué pieza del curso ejecuta con los permisos de su dueño? Caso 3: 'o pasa todo o no pasa nada' ya tiene nombre técnico.","Caso 4: la huella automática del valor viejo es el journaling — ¿qué pieza se dispara sola ante el UPDATE y conoce :OLD y :NEW?","Caso 5: la escalera de intervención — ¿qué se corrige ANTES de pensar en índices o hints cuando acaba de haber una carga masiva?"],"successMessage":"Sistema en operación: CHECK vigilando, procedure como aduana, una sola transacción atómica, trigger llevando el diario y estadísticas frescas. Las seis reglas de la directora quedaron implementadas — falta la validación final.","failMessage":"Revisa: caso2=procedure (EXECUTE sin permisos de tabla) · caso3=una (unidad de negocio = una transacción) · caso4=trigger (el journaling automático) · caso5=estadisticas (la carga invalidó la foto)."}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm11-l05-practica-operacion';

-- ═════════════════════════════════════════════════════════════════════
-- L06 · La matriz CRUD y el cierre
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"La validación final: la matriz del programa","body":"Antes de declarar victoria, el control de calidad del m3b: la MATRIZ CRUD del programa. Procesos en filas (recibir lote, capturar aplicación, reportar cobertura, auditar cambios), entidades en columnas (vacuna, lote, aplicación, paciente). Al llenarla, dos hallazgos — y así se ven los hallazgos reales: PRIMERO, la columna PACIENTE no tiene C en ningún proceso del programa… y está BIEN: los pacientes nacen en el sistema central del hospital; nuestro programa solo los Lee — el 'hueco' se resuelve por integración, no inventando una tabla. SEGUNDO, la columna VACUNA no tiene U ni D: ¿el catálogo jamás se corrige? Ese sí era un hueco — faltaba el proceso 'mantener catálogo' (quién lo hace, con qué permisos). La matriz no diseña: DELATA. Diez minutos de tabla encontraron lo que tres revisiones al vuelo dejaron pasar."}$j$),
  (2, 'texto', $j${"title":"El mapa del viaje completo","body":"Mira el proyecto terminado y cuenta las piezas: el BRIEF se volvió requisitos (m1-m2); las reglas se volvieron ENTIDADES con identidad, una relación identificadora, el tiempo en un UID y un arco (m2, m3a); la tentación de copiar nombre_vacuna murió por la 3FN (m3); el mapeo produjo una PK compuesta y FKs nombradas (m3b, m04); el tablero de cobertura cruzó tres tablas con agregación (m05-m07); la operación quedó atómica (m08), protegida por una aduana con mínimo privilegio (m08, m10), auditada por un trigger legítimo (m10) y con estadísticas frescas para el optimizador (m09); y la matriz CRUD validó el conjunto (m3b). Ese es el oficio completo: no trece temas sueltos — UNA disciplina donde cada pieza sostiene a las demás. La próxima vez que alguien te entregue un párrafo de negocio, ya sabes exactamente qué hacer con él."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"En la matriz CRUD del programa, la columna PACIENTE quedó sin C — y el equipo decidió que está BIEN. ¿Cuál es la justificación válida?","options":["Las matrices siempre tienen huecos","Los pacientes NACEN en otro sistema (el central del hospital): el programa solo los lee — el hallazgo se resuelve por INTEGRACIÓN documentada, no inventando una tabla","Los pacientes no importan al programa","Se les olvidó llenarla"],"correctIndex":1,"feedback":{"correct":"Correcto. La matriz delata; el equipo DECIDE: un sin-C es legítimo cuando la entidad nace fuera — y esa decisión se documenta.","incorrect":"El hueco de C es válido si la entidad se crea en otro sistema: la matriz obliga a hacer explícita esa frontera de integración."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"La columna VACUNA quedó sin U ni D en la matriz — y esto SÍ se marcó como hueco. ¿Por qué?","options":["Porque toda columna debe tener las cuatro letras","Porque el catálogo NECESITA mantenimiento (corregir nombres, retirar vacunas) y ningún proceso lo cubría: faltaba modelar 'mantener catálogo', con su responsable y sus permisos","Porque las vacunas se borran solas","Porque U y D son opcionales"],"correctIndex":1,"feedback":{"correct":"Correcto. El mismo síntoma (letras faltantes), diagnóstico opuesto al de PACIENTE: aquí el proceso faltaba de verdad. La matriz delata; el análisis decide.","incorrect":"Un catálogo sin proceso de mantenimiento es un hueco real: alguien corregirá 'a mano' (sin permisos ni auditoría) el día que urja."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"Repaso del ensamble: para 'la dosis jamás negativa', 'la huella de cambios' y 'las brigadas sin tocar tablas', las herramientas correctas fueron…","options":["Trigger, trigger y trigger","CHECK (declarativa antes que trigger) · TRIGGER con :OLD/:NEW (el journaling legítimo) · PROCEDURE con GRANT EXECUTE (la aduana del mínimo privilegio)","Vista, índice y hint","CHECK para todo"],"correctIndex":1,"feedback":{"correct":"Correcto. Tres reglas, tres herramientas distintas — cada una en su lugar exacto: así se ve el criterio.","incorrect":"Cada regla con SU pieza: la declarativa donde alcanza, el trigger donde es legítimo (auditoría), el procedure como puerta única."}}$j$),
  (6, 'resumen', $j${"title":"Resumen — El proyecto (y el curso)","points":["La matriz CRUD DELATA huecos; el análisis decide: sin-C legítimo (nace fuera: integración) vs proceso faltante real.","El proyecto usó las trece regiones como UNA disciplina: del párrafo de negocio al sistema operando.","Modelo con identidad, tiempo en el UID y 3FN → esquema con PK compuesta y FKs nombradas.","Consultas que recorren el modelo → operación atómica, con aduana, auditoría y estadísticas frescas.","La próxima vez que te entreguen un párrafo de negocio, ya sabes qué hacer con él. Queda una puerta: el examen final."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm11-l06-crud-cierre';

-- ═════════════════════════════════════════════════════════════════════
-- X01 · Examen final del curso (jefe de la región final)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"La región final","body":"Byte está frente a la última puerta — y detrás no hay otra región: está el título. Once preguntas cruzan TODO el viaje: modelado, normalización, esquema, consultas, transacciones, seguridad, optimización y PL/SQL, todas vestidas con el proyecto que acabas de construir. Las que falles volverán al final hasta que las domines. Es todo lo que sabes. Adelante."}$j$),
  (2, 'quiz', $j${"variant":"multiple_choice","prompt":"El UID de APLICACIÓN es paciente + lote + fecha. ¿Qué caso de negocio se ROMPERÍA si la fecha saliera del UID?","options":["El reporte de cobertura","El REFUERZO: la misma pareja paciente-lote en otra fecha sería un 'duplicado' prohibido — el tiempo en el UID habilita la repetición legítima","Las campañas en unidad móvil","La caducidad de los lotes"],"correctIndex":1,"feedback":{"correct":"Correcto. El modelado temporal del m3a sosteniendo un requisito real: sin la fecha, el refuerzo es imposible de registrar.","incorrect":"Sin fecha en el UID, la segunda dosis de la misma pareja viola la unicidad: el tiempo en la identidad ES el requisito del refuerzo."}}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"Guardar nombre_vacuna dentro de APLICACIONES 'para ahorrar un JOIN' — el análisis completo del curso:","options":["Buena idea: los JOINs son caros","Viola la 3FN (transitiva vía lote): la copia se desincroniza con las anomalías del m03, y el JOIN que 'ahorra' es exactamente el camino que el modelo pavimentó — normalización lógica primero; si el rendimiento REAL lo exigiera, se mediría antes de decidir","Viola la 1FN","Da igual"],"correctIndex":1,"feedback":{"correct":"Correcto. La 3FN, las anomalías y la disciplina de medir-antes-de-desnormalizar, en una sola decisión.","incorrect":"El dato de la vacuna viaja vía lote: copiarlo es la transitiva del m03 con sus anomalías. Y 'los JOINs son caros' se MIDE, no se supone."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"La PK de APLICACIONES tiene tres columnas y las FKs se llaman apl_pac_fk y apl_lote_fk. ¿Qué dos reglas del curso están trabajando ahí?","options":["Ninguna: es estilo personal","La PK compuesta implanta el UID con tiempo (compuestas SOLO a nivel tabla), y las constraints NOMBRADAS convierten los errores de producción en mensajes legibles (nada de SYS_C…)","Las PK siempre llevan tres columnas","Los nombres son aleatorios"],"correctIndex":1,"feedback":{"correct":"Correcto. El mapeo del m3b y la nomenclatura del m04, sosteniendo juntos una tabla real.","incorrect":"PK compuesta = decisión de identidad hecha estructura (nivel tabla obligatorio); constraint nombrada = el error que se entiende solo."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"Para vaciar la tabla de PRUEBAS de aplicaciones antes de la carga real, un colega usa TRUNCATE 'porque luego hacemos ROLLBACK si algo sale mal'. ¿El error?","options":["TRUNCATE no vacía tablas","TRUNCATE es DDL con COMMIT IMPLÍCITO: no hay ROLLBACK posible después — si la red de seguridad importa, la herramienta era DELETE (DML reversible antes de confirmar)","El TRUNCATE necesita WHERE","No hay error"],"correctIndex":1,"feedback":{"correct":"Correcto. La precisión vinculante del m04: la clasificación DDL/DML decide la reversibilidad — y aquí decidía la herramienta.","incorrect":"El plan 'TRUNCATE + ROLLBACK' es imposible: el TRUNCATE se confirma solo. Red de seguridad requerida → DELETE."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"'Pacientes del censo que JAMÁS han recibido una aplicación' — y la subconsulta de aplicaciones puede traer nulos. ¿La consulta profesional?","options":["NOT IN sin más: es la más corta","NOT EXISTS con subconsulta correlada (o el anti-join LEFT + IS NULL): NOT IN con un nulo en la lista devuelve VACÍO en silencio — la trampa del m06","INTERSECT","Un CROSS JOIN filtrado"],"correctIndex":1,"feedback":{"correct":"Correcto. La trampa de tres valores, esquivada con las dos formas inmunes: NOT EXISTS o el anti-join.","incorrect":"NOT IN + nulo = resultado vacío sin error: los 'sin aplicación' se buscan con NOT EXISTS o LEFT JOIN + IS NULL."}}$j$),
  (7, 'quiz', $j${"variant":"multiple_choice","prompt":"En el tablero de cobertura: 'solo aplicaciones de 2026' y 'solo vacunas con 100+ dosis'. ¿Dónde va cada condición y por qué?","options":["Ambas en el HAVING","La fecha en el WHERE (condición de FILA, filtra antes de agrupar) y el COUNT(*) >= 100 en el HAVING (condición de AGREGADO, solo existe después del GROUP BY)","Ambas en el WHERE","La fecha en el ORDER BY"],"correctIndex":1,"feedback":{"correct":"Correcto. Las dos aduanas del m07, cada condición en su momento del orden lógico de ejecución.","incorrect":"El orden lógico decide: la fila se filtra antes de agrupar (WHERE); el conteo solo existe después (HAVING)."}}$j$),
  (8, 'quiz', $j${"variant":"multiple_choice","prompt":"A media captura, la tableta de la brigada pierde señal y la sesión muere: la aplicación se insertó pero el descuento del lote no se ejecutó. Con la transacción bien dibujada (R4), ¿qué encuentra la base al reconectar?","options":["La aplicación sin descuento: hay que corregir a mano","NADA a medias: la sesión caída hizo ROLLBACK de lo no confirmado — la aplicación huérfana jamás existió, y la brigada simplemente recaptura completo","Ambas operaciones aplicadas","Un deadlock"],"correctIndex":1,"feedback":{"correct":"Correcto. La atomicidad y la cuarta frontera de la transacción (caída = rollback): el requisito de la mala señal, resuelto por diseño.","incorrect":"La caída revierte lo no confirmado: con ambas operaciones en UNA transacción, el estado a medias es imposible — exactamente para eso se dibujó así."}}$j$),
  (9, 'quiz', $j${"variant":"multiple_choice","prompt":"El diseño de acceso para las brigadas fue: rol con CREATE SESSION + GRANT EXECUTE sobre registrar_aplicacion, y NADA más. ¿Qué previene exactamente ese diseño?","options":["Que las brigadas trabajen","El UPDATE/DELETE suelto sobre las tablas (sin WHERE, sin validaciones, sin auditoría): solo existe el camino pavimentado del procedure — mínimo privilegio ejecutado","Los deadlocks","Las consultas lentas"],"correctIndex":1,"feedback":{"correct":"Correcto. La tabla cerrada, la aduana única: el daño posible se acota al camino con validaciones.","incorrect":"EXECUTE sin permisos de tabla = la única puerta es el procedure: el DML accidental o malicioso directo se vuelve imposible."}}$j$),
  (10, 'quiz', $j${"variant":"multiple_choice","prompt":"El tablero corre lento y su plan muestra un FULL TABLE SCAN sobre aplicaciones (lee el 90% de la tabla para el acumulado anual). Un colega exige 'quitar ese FTS'. Tu respuesta con el m09:","options":["Tiene razón: todo FTS se elimina","Ese FTS es HONRADO: para leer el 90% de la tabla, la lectura de corrido gana a millones de saltos por índice — el diagnóstico es si el plan corresponde a lo pedido, y aquí corresponde. Se revisan estadísticas y estimaciones antes de tocar nada","Se agrega un hint /*+ INDEX */ inmediatamente","Se borra el índice"],"correctIndex":1,"feedback":{"correct":"Correcto. La precisión vinculante del m09 aplicada con criterio: el FTS del acumulado anual es la ruta correcta.","incorrect":"FTS no es mala palabra: para cosechas del 90%, es la estrategia óptima. El reflejo anti-FTS delata al repetidor de mitos."}}$j$),
  (11, 'quiz', $j${"variant":"multiple_choice","prompt":"El trigger de auditoría de lotes guarda :OLD.cantidad y :NEW.cantidad en cada UPDATE. ¿Por qué un TRIGGER y no una CHECK, si la regla es 'dejar huella'?","options":["Porque las CHECK son lentas","Porque 'dejar huella' NO es una condición que una fila cumple: es una ACCIÓN sobre otra tabla — fuera del alcance de las declarativas: el uso legítimo exacto del trigger (el journaling del m3a)","Porque los triggers son más modernos","Debería ser CHECK"],"correctIndex":1,"feedback":{"correct":"Correcto. La regla 'declarativas antes que triggers' tiene su excepción precisa: la auditoría es acción, no condición.","incorrect":"La CHECK valida condiciones de la fila; escribir en la bitácora es una acción — territorio legítimo del trigger con :OLD/:NEW."}}$j$),
  (12, 'quiz', $j${"variant":"multiple_choice","prompt":"La pregunta final del curso — la entrevista: 'nárrame tu proyecto de vacunación de punta a punta'. La respuesta que resume el oficio:","options":["'Hice unas tablas y unos SELECT'","'Del brief extraje entidades y reglas; modelé con identidad compuesta, el tiempo en el UID del refuerzo, 3FN y un arco; lo mapeé a un esquema con PK compuesta y constraints nombradas; construí las consultas sobre el modelo normalizado; dibujé la transacción en la frontera del negocio; cerré las tablas tras un procedure con mínimo privilegio; audité con un trigger legítimo; mantuve estadísticas frescas y validé todo con la matriz CRUD — cada decisión tiene su porqué y puedo defenderla'","'Usé Oracle porque me lo pidieron'","'Copié un esquema de internet y lo adapté'"],"correctIndex":1,"feedback":{"correct":"Impecable. Trece regiones, una disciplina, cero decisiones sin porqué. Curso terminado: ese es el nivel con el que sales.","incorrect":"La narrativa senior recorre el SDLC completo con cada decisión justificada: modelo → esquema → consultas → operación → validación. Todo lo demás es la respuesta corta de quien no diseñó."}}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm11-x01-examen';
